import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { FormBuilder, FormGroup, FormsModule, ReactiveFormsModule, Validators } from '@angular/forms';
import { ModuloService } from '../../../core/services/modulo.service';
import { MaterialService } from '../../../core/services/material.service';
import { ModuloResponse } from '../../../core/models/modulo.model';
import { MaterialResponse } from '../../../core/models/material.model';
import { AuthService } from '../../../core/services/auth.service';

@Component({
  selector: 'app-materiales',
  standalone: true,
  imports: [
    CommonModule,
    RouterModule,
    FormsModule,
    ReactiveFormsModule
  ],
  templateUrl: './materiales.component.html',
  styleUrls: ['./materiales.component.css']
})
export class MaterialesComponent implements OnInit {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private moduloService = inject(ModuloService);
  private materialService = inject(MaterialService);
  private fb = inject(FormBuilder);
  private authService = inject(AuthService);

  moduloId!: number;
  modulo: ModuloResponse | null = null;
  materiales: MaterialResponse[] = [];
  filteredMateriales: MaterialResponse[] = [];
  searchQuery = '';

  // Modal controls
  showMaterialModal = false;
  isEditMode = false;
  isFormSubmitting = false;
  isFormSubmitted = false;
  modalErrorMsg = '';

  selectedMaterial: MaterialResponse | null = null;
  selectedFile: File | null = null;

  materialForm: FormGroup = this.fb.group({
    nombre: ['', [Validators.required]],
    estado: [true]
  });

  ngOnInit(): void {
    this.route.paramMap.subscribe(params => {
      const idParam = params.get('id');
      if (idParam) {
        this.moduloId = Number(idParam);
        this.loadModuloData();
      } else {
        this.router.navigate(['/dashboard/cursos']);
      }
    });
  }

  loadModuloData(): void {
    this.moduloService.obtenerModulo(this.moduloId).subscribe({
      next: (data) => {
        this.modulo = data;
        this.loadMateriales();
      },
      error: (err) => {
        console.error('Error al obtener modulo', err);
        this.router.navigate(['/dashboard/cursos']);
      }
    });
  }

  loadMateriales(): void {
    this.materialService.listarMaterialesPorModulo(this.moduloId).subscribe({
      next: (data) => {
        this.materiales = data;
        this.applyFilter();
      },
      error: (err) => {
        console.error('Error al listar materiales', err);
      }
    });
  }

  applyFilter(): void {
    if (!this.searchQuery.trim()) {
      this.filteredMateriales = [...this.materiales];
      return;
    }

    const query = this.searchQuery.toLowerCase();
    this.filteredMateriales = this.materiales.filter(m => 
      m.nombre.toLowerCase().includes(query)
    );
  }

  openCreateModal(): void {
    this.isEditMode = false;
    this.modalErrorMsg = '';
    this.selectedMaterial = null;
    this.selectedFile = null;
    this.isFormSubmitted = false;
    this.isFormSubmitting = false;
    this.materialForm.reset({
      nombre: '',
      estado: true
    });
    this.showMaterialModal = true;
  }

  openEditModal(material: MaterialResponse): void {
    this.isEditMode = true;
    this.modalErrorMsg = '';
    this.selectedMaterial = material;
    this.selectedFile = null;
    this.isFormSubmitted = false;
    this.isFormSubmitting = false;

    this.materialForm.patchValue({
      nombre: material.nombre,
      estado: material.estado
    });
    this.showMaterialModal = true;
  }

  closeMaterialModal(): void {
    this.showMaterialModal = false;
    this.isFormSubmitting = false;
    this.isFormSubmitted = false;
    this.selectedFile = null;
  }

  onFileSelected(event: any): void {
    const file = event.target.files?.[0];
    if (file) {
      // Validate file size (10MB limit)
      if (file.size > 10 * 1024 * 1024) {
        this.modalErrorMsg = 'El archivo supera el límite de tamaño permitido (10MB).';
        this.selectedFile = null;
        return;
      }
      this.modalErrorMsg = '';
      this.selectedFile = file;
    }
  }

  toggleEstado(material: MaterialResponse): void {
    const nuevoEstado = !material.estado;
    this.materialService.cambiarEstado(material.id, nuevoEstado).subscribe({
      next: () => {
        material.estado = nuevoEstado;
      },
      error: (err) => {
        console.error('Error al cambiar estado del material', err);
      }
    });
  }

  onSubmit(): void {
    this.isFormSubmitted = true;

    if (this.materialForm.invalid) {
      return;
    }

    if (!this.isEditMode && !this.selectedFile) {
      return;
    }

    this.isFormSubmitting = true;
    this.modalErrorMsg = '';

    const nombre = this.materialForm.value.nombre;

    if (this.isEditMode && this.selectedMaterial) {
      this.materialService.editarMaterial(this.selectedMaterial.id, nombre, this.selectedFile || undefined).subscribe({
        next: (res) => {
          const stateChanged = this.materialForm.value.estado !== this.selectedMaterial!.estado;
          if (stateChanged) {
            this.materialService.cambiarEstado(this.selectedMaterial!.id, this.materialForm.value.estado).subscribe({
              next: () => {
                this.loadMateriales();
                this.closeMaterialModal();
              },
              error: (err) => this.handleError(err)
            });
          } else {
            this.loadMateriales();
            this.closeMaterialModal();
          }
        },
        error: (err) => this.handleError(err)
      });
    } else {
      this.materialService.subirMaterial(this.moduloId, nombre, this.selectedFile!).subscribe({
        next: () => {
          this.loadMateriales();
          this.closeMaterialModal();
        },
        error: (err) => this.handleError(err)
      });
    }
  }

  getFileIcon(tipo: string): string {
    const t = (tipo || '').toLowerCase();
    if (t.includes('pdf')) {
      return 'picture_as_pdf';
    }
    if (t.includes('word') || t.includes('msword') || t.includes('document')) {
      return 'description';
    }
    if (t.includes('image') || t.includes('jpeg') || t.includes('jpg') || t.includes('png')) {
      return 'image';
    }
    return 'article';
  }

  getCleanFileType(tipo: string): string {
    const t = (tipo || '').toLowerCase();
    if (t.includes('pdf')) return 'PDF';
    if (t.includes('vnd.openxmlformats-officedocument.wordprocessingml.document')) return 'DOCX';
    if (t.includes('msword') || t.includes('word')) return 'DOC';
    if (t.includes('jpeg') || t.includes('jpg')) return 'JPG';
    if (t.includes('png')) return 'PNG';
    return 'Archivo';
  }

  formatBytes(bytes: number): string {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  }

  getToken(): string | null {
    return this.authService.getToken();
  }

  private handleError(err: any): void {
    this.isFormSubmitting = false;
    this.modalErrorMsg = err.error?.message || 'Error al procesar el material.';
  }
}
<div class="space-y-8 font-body" *ngIf="modulo">

  <!-- Back button -->
  <div class="flex items-center">
    <a 
      [routerLink]="['/dashboard/cursos', modulo.cursoId]" 
      class="flex items-center gap-1.5 text-xs font-bold text-slate-500 hover:text-slate-900 uppercase tracking-widest transition-colors">
      <span class="material-symbols-outlined text-sm">arrow_back</span>
      <span>Volver a Módulos del Curso</span>
    </a>
  </div>

  <!-- Header Banner: Structured Course and Module context -->
  <div class="border border-slate-200 p-8 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
    <div>
      <div class="flex items-center gap-2">
        <span class="text-[9px] font-black text-slate-400 bg-slate-100 border border-slate-200 px-2 py-0.5 uppercase tracking-widest rounded-none">
          Curso: {{ modulo.cursoNombre }}
        </span>
      </div>
      <h1 class="text-2xl font-black text-slate-900 mt-2 tracking-tight uppercase leading-none">
        Módulo {{ modulo.orden }}: {{ modulo.nombre }}
      </h1>
      <p class="text-slate-500 text-xs mt-1">Gestión de guías, presentaciones, PDFs y materiales didácticos de descarga.</p>
    </div>
    <button 
      (click)="openCreateModal()" 
      class="flex items-center gap-2 px-4 py-2.5 bg-slate-900 text-white font-bold text-xs uppercase tracking-widest hover:bg-slate-800 transition-colors rounded-none">
      <span class="material-symbols-outlined text-sm">upload_file</span>
      <span>Subir Material</span>
    </button>
  </div>

  <!-- Material Workspace -->
  <div class="border border-slate-200 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] overflow-hidden">
    <!-- Filter bar -->
    <div class="p-4 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
      <div class="relative w-full max-w-xs">
        <span class="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
          <span class="material-symbols-outlined text-base">search</span>
        </span>
        <input 
          [(ngModel)]="searchQuery"
          (input)="applyFilter()"
          class="block w-full pl-9 pr-3 py-2 border border-slate-300 bg-white text-slate-800 placeholder-slate-400 focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary text-xs rounded-none" 
          placeholder="Buscar material por nombre...">
      </div>
      <span class="text-[10px] font-bold text-slate-400 uppercase tracking-wider">
        {{ filteredMateriales.length }} materiales en el módulo
      </span>
    </div>

    <!-- Materials Table -->
    <div class="overflow-x-auto">
      <table class="w-full text-left border-collapse text-xs">
        <thead>
          <tr class="border-b border-slate-200 bg-slate-100/60 text-slate-700 font-bold uppercase tracking-wider text-[10px]">
            <th class="p-4">Archivo</th>
            <th class="p-4 w-32">Tipo</th>
            <th class="p-4 w-32">Tamaño</th>
            <th class="p-4 w-32">Estado</th>
            <th class="p-4 text-right w-44">Acciones</th>
          </tr>
        </thead>
        <tbody class="divide-y divide-slate-100">
          <!-- Empty state -->
          <tr *ngIf="filteredMateriales.length === 0">
            <td colspan="5" class="p-12 text-center text-slate-400">
              <span class="material-symbols-outlined text-4xl mb-2 text-slate-300">folder_open</span>
              <p class="font-medium text-xs">Este módulo todavía no contiene materiales de descarga.</p>
            </td>
          </tr>
          <!-- Rows -->
          <tr *ngFor="let mat of filteredMateriales" class="hover:bg-slate-50 transition-colors">
            <!-- Archivo (Name & Link) -->
            <td class="p-4">
              <div class="flex items-center gap-2.5">
                <span class="material-symbols-outlined text-slate-400 text-lg">
                  {{ getFileIcon(mat.tipoArchivo) }}
                </span>
                <span class="font-bold text-slate-900 truncate max-w-sm">{{ mat.nombre }}</span>
              </div>
            </td>
            <!-- Tipo -->
            <td class="p-4 font-mono text-[10px] text-slate-500 uppercase">
              {{ getCleanFileType(mat.tipoArchivo) }}
            </td>
            <!-- Tamaño -->
            <td class="p-4 font-mono text-[10px] text-slate-500">
              {{ formatBytes(mat.pesoBytes) }}
            </td>
            <!-- Estado -->
            <td class="p-4">
              <span [ngClass]="mat.estado ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-red-50 text-red-700 border-red-200'" class="px-2.5 py-1 text-[9px] font-black uppercase tracking-wider border rounded-none">
                {{ mat.estado ? 'ACTIVO' : 'INACTIVO' }}
              </span>
            </td>
            <!-- Acciones -->
            <td class="p-4 text-right">
              <div class="inline-flex gap-2">
                <!-- Download direct file stream -->
                <a 
                  [href]="mat.archivoUrl + '?token=' + getToken()" 
                  download
                  title="Descargar Archivo"
                  class="p-1.5 border border-slate-200 hover:border-slate-400 hover:bg-slate-50 text-slate-600 rounded-none transition-colors">
                  <span class="material-symbols-outlined text-base block">download</span>
                </a>
                <button 
                  (click)="openEditModal(mat)" 
                  title="Editar Material"
                  class="p-1.5 border border-slate-200 hover:border-slate-400 hover:bg-slate-50 text-slate-600 rounded-none transition-colors">
                  <span class="material-symbols-outlined text-base block">edit</span>
                </button>
                <button 
                  (click)="toggleEstado(mat)" 
                  [title]="mat.estado ? 'Desactivar' : 'Activar'"
                  [ngClass]="mat.estado ? 'border-red-200 text-red-600 hover:bg-red-50' : 'border-emerald-200 text-emerald-600 hover:bg-emerald-50'"
                  class="p-1.5 border rounded-none transition-colors">
                  <span class="material-symbols-outlined text-base block">
                    {{ mat.estado ? 'block' : 'check_circle' }}
                  </span>
                </button>
              </div>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>

  <!-- Create/Edit Material Modal -->
  <div *ngIf="showMaterialModal" class="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
    <div class="w-full max-w-md bg-white border border-slate-200 shadow-2xl rounded-none overflow-hidden relative">
      <!-- Modal Header -->
      <div class="px-6 py-4 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
        <h3 class="text-sm font-black text-slate-900 uppercase tracking-wider">
          {{ isEditMode ? 'Modificar Material' : 'Subir Material de Estudio' }}
        </h3>
        <button (click)="closeMaterialModal()" class="text-slate-400 hover:text-slate-600">
          <span class="material-symbols-outlined text-lg">close</span>
        </button>
      </div>

      <!-- Modal Form -->
      <form [formGroup]="materialForm" (ngSubmit)="onSubmit()" class="p-6 space-y-4">
        <div *ngIf="modalErrorMsg" class="flex items-start gap-2 bg-red-50 border border-red-200 text-red-800 p-3 rounded-none text-[11px] font-semibold">
          <span class="material-symbols-outlined text-red-600 text-base">warning</span>
          <span>{{ modalErrorMsg }}</span>
        </div>

        <!-- Nombre -->
        <div>
          <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Nombre del Recurso *</label>
          <input 
            formControlName="nombre" 
            type="text" 
            class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary"
            placeholder="Ej. Guía Teórica de Fórmulas">
          <p *ngIf="materialForm.get('nombre')?.invalid && materialForm.get('nombre')?.touched" class="text-[10px] text-red-600 mt-1">El nombre es obligatorio.</p>
        </div>

        <!-- File Upload Selector / Drag Drop area -->
        <div>
          <label class="block text-[10px] font-bold text-slate-700 mb-1.5 uppercase tracking-widest">Archivo *</label>

          <!-- Boxed Area -->
          <div 
            class="border-2 border-dashed border-slate-300 p-6 text-center bg-slate-50/50 hover:bg-slate-50 transition-all relative rounded-none select-none cursor-pointer">
            <input 
              type="file" 
              (change)="onFileSelected($event)"
              accept=".pdf,.doc,.docx,.jpg,.jpeg,.png"
              class="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10">

            <div class="space-y-2">
              <span class="material-symbols-outlined text-3xl text-slate-400">cloud_upload</span>
              <div class="text-xs font-bold text-slate-700">
                {{ selectedFile ? selectedFile.name : 'Arrastre o seleccione un archivo' }}
              </div>
              <p class="text-[9px] text-slate-400">PDF, DOC, DOCX, JPG o PNG (Max. 10MB)</p>
            </div>
          </div>

          <!-- File selection warning for Edit Mode -->
          <p *ngIf="isEditMode" class="text-[9px] text-slate-400 mt-1.5">Deje vacío si no desea modificar el archivo físico actual.</p>
          <p *ngIf="!isEditMode && !selectedFile && isFormSubmitted" class="text-[10px] text-red-600 mt-1">El archivo es obligatorio.</p>
        </div>

        <!-- Estado (Edit mode only) -->
        <div *ngIf="isEditMode">
          <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Estado</label>
          <select 
            formControlName="estado" 
            class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary">
            <option [ngValue]="true">ACTIVO</option>
            <option [ngValue]="false">INACTIVO</option>
          </select>
        </div>

        <!-- Form Buttons -->
        <div class="pt-4 border-t border-slate-100 flex justify-end gap-3">
          <button 
            type="button" 
            (click)="closeMaterialModal()" 
            class="px-4 py-2 border border-slate-300 bg-white text-slate-700 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 transition-colors rounded-none">
            Cancelar
          </button>
          <button 
            type="submit" 
            [disabled]="isFormSubmitting" 
            class="px-4 py-2 bg-slate-900 text-white font-bold text-xs uppercase tracking-widest hover:bg-slate-800 transition-colors rounded-none disabled:opacity-55">
            {{ isFormSubmitting ? 'Subiendo...' : 'Subir Material' }}
          </button>
        </div>
      </form>
    </div>
  </div>

</div>
